(async function(params) {
  const { width, height, maxIterations } = params;
  const startTime = performance.now();
  let operations = 0;
  let insideSet = 0;
  let outsideSet = 0;

  const zoom = 1.5;
  const offsetX = -0.7;
  const offsetY = 0.0;
  const scaleX = (3.5 / zoom) / width;
  const scaleY = (2.0 / zoom) / height;

  const pixels = new Uint32Array(width * height);

  for (let py = 0; py < height; py++) {
    for (let px = 0; px < width; px++) {
      const cx = (px - width / 2) * scaleX + offsetX;
      const cy = (py - height / 2) * scaleY + offsetY;
      let x = 0, y = 0, iteration = 0;

      while (x*x + y*y <= 4 && iteration < maxIterations) {
        const xTemp = x*x - y*y + cx;
        y = 2*x*y + cy;
        x = xTemp;
        iteration++;
        operations++;
      }

      if (iteration === maxIterations) {
        insideSet++;
      } else {
        outsideSet++;
      }

      pixels[py * width + px] = iteration;
    }

    if (py % 100 === 0 && py > 0) {
      await new Promise(resolve => setTimeout(resolve, 0));
    }
  }

  const took_ms = performance.now() - startTime;
  const mpxPerSec = (width * height) / (took_ms / 1000) / 1000000;

  return {
    pixels: width * height,
    resolution: width + 'x' + height,
    iterations: maxIterations,
    operations,
    insideSet,
    outsideSet,
    convergenceRatio: (insideSet / (width * height) * 100).toFixed(2) + '%',
    took_ms: Math.round(took_ms),
    throughput: (width * height) / (took_ms / 1000),
    mpxPerSec: mpxPerSec.toFixed(3) + ' Mpx/s',
    estimatedMemory: ((width * height * 4) / 1024 / 1024).toFixed(2) + ' MB'
  };
})
